    void initFromSalesTable(SalesTable _salesTable, boolean _ignoreInventDim)
    {
        next initFromSalesTable(_salesTable, _ignoreInventDim);

        DimensionAttributeValue dimAttrValue;
        DimensionAttributeValueSetStorage storage;
        SalesTable salesTable;

        dimAttrValue = DimensionAttributeValue::find(_salesTable.UBSProjectDim);

        storage = DimensionAttributeValueSetStorage::find(salesLine.DefaultDimension);

        if(dimAttrValue)
        {
            storage.addItem(dimAttrValue);
            salesLine.DefaultDimension = storage.save();
        }
    }
